public class BankAccount {
    // Fields (state) — each object gets its own copies
    private String owner;
    private double balance;
    private String accountId;

    // Constructor — initializes object state
    public BankAccount(String owner, double initialBalance) {
        this.owner = owner;
        this.balance = initialBalance;
        this.accountId = "ACC" + System.nanoTime();
    }

    // Methods (behavior) — operate on this instance's fields
    public void deposit(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Amount must be positive");
        balance += amount;
    }

    public boolean withdraw(double amount) {
        if (amount > balance) return false; // invariant: no negative balance
        balance -= amount;
        return true;
    }

    public double getBalance() { return balance; }
    public String getOwner()   { return owner; }

    @Override
    public String toString() {
        return accountId + " [" + owner + "]: $" + String.format("%.2f", balance);
    }

    public static void main(String[] args) {
        BankAccount alice = new BankAccount("Alice", 1000.0);
        BankAccount bob   = new BankAccount("Bob",   500.0);

        alice.deposit(250.0);
        boolean ok = bob.withdraw(600.0); // fails — insufficient funds

        System.out.println(alice);   // [Alice]: $1250.00
        System.out.println(bob);     // [Bob]: $500.00
        System.out.println(ok);      // false
    }
}

public class Rectangle {
    private double width;
    private double height;
    private String label;

    // USE 1: this.field to disambiguate field from param
    public Rectangle(double width, double height, String label) {
        this.width  = width;   // field vs parameter — same name!
        this.height = height;
        this.label  = label;
    }

    // USE 2: this(...) constructor chaining — must be first statement
    public Rectangle(double side) {
        this(side, side, "Square");
    }

    // USE 3: return this — fluent method chaining
    public Rectangle scale(double factor) {
        this.width  *= factor;
        this.height *= factor;
        return this;  // same object returned
    }

    public Rectangle relabel(String newLabel) {
        this.label = newLabel;
        return this;
    }

    public double area() { return width * height; }

    @Override
    public String toString() {
        return label + " [" + width + " x " + height + "] area=" + area();
    }

    public static void main(String[] args) {
        Rectangle r = new Rectangle(4.0, 3.0, "Original");
        System.out.println(r); // Original [4.0 x 3.0] area=12.0

        r.scale(2.0).relabel("Doubled"); // method chaining
        System.out.println(r); // Doubled [8.0 x 6.0] area=48.0

        Rectangle sq = new Rectangle(5.0); // constructor chaining
        System.out.println(sq); // Square [5.0 x 5.0] area=25.0
    }
}

public class Counter {
    // STATIC: one copy shared by ALL instances — lives in Method Area
    private static int totalCreated = 0;
    private static final String VERSION = "1.0";

    // INSTANCE: each object has its OWN copy — lives on heap
    private int count;
    private final String name;

    public Counter(String name) {
        this.name  = name;
        this.count = 0;
        totalCreated++; // shared across all — incremented by every new Counter
    }

    public void increment()          { count++; }            // instance method
    public int  getCount()           { return count; }        // reads own field
    public static int getTotal()     { return totalCreated; } // static — no 'this'
    public static String getVersion(){ return VERSION; }

    @Override
    public String toString() {
        return name + ": count=" + count + " (total=" + totalCreated + ")";
    }

    public static void main(String[] args) {
        System.out.println(Counter.getTotal());    // 0
        System.out.println(Counter.getVersion());  // 1.0

        Counter a = new Counter("A"); // totalCreated=1
        Counter b = new Counter("B"); // totalCreated=2

        a.increment(); a.increment(); // a.count=2
        b.increment();                // b.count=1

        System.out.println(a); // A: count=2 (total=2)
        System.out.println(b); // B: count=1 (total=2)
        System.out.println(Counter.getTotal()); // 2
    }
}

import java.util.*;

public class Product {
    private final String id;
    private final String name;
    private final double price;

    public Product(String id, String name, double price) {
        this.id = id; this.name = name; this.price = price;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;        // same reference — shortcut
        if (!(o instanceof Product)) return false;
        Product p = (Product) o;
        return id.equals(p.id);            // logical equality: same ID
    }

    // CONTRACT: if equals() → true, hashCode() MUST be equal
    @Override
    public int hashCode() {
        return Objects.hash(id);           // must use SAME field(s) as equals
    }

    @Override
    public String toString() { return id + ":" + name; }

    public static void main(String[] args) {
        Product p1 = new Product("P001", "Widget", 9.99);
        Product p2 = new Product("P001", "Widget", 9.99); // same ID, new object
        Product p3 = new Product("P002", "Gadget", 14.99);

        System.out.println(p1 == p2);       // false — different heap references
        System.out.println(p1.equals(p2));  // true  — same logical ID
        System.out.println(p1.equals(p3));  // false — different ID

        // HashMap uses hashCode to find bucket, equals to confirm match
        Map<Product, Integer> stock = new HashMap<>();
        stock.put(p1, 100);
        System.out.println(stock.get(p2)); // 100 — p2 finds p1's entry!

        // HashSet deduplication
        Set<Product> catalog = new HashSet<>(List.of(p1, p2, p3));
        System.out.println(catalog.size()); // 2 — p1 and p2 are 'equal'
    }
}

public class ObjectLifecycle {

    static class Resource implements AutoCloseable {
        String name;
        boolean open;

        Resource(String name) {
            this.name = name;
            this.open = true;
            System.out.println("CREATED: " + name);
        }

        void use() {
            if (!open) throw new IllegalStateException(name + " is closed");
            System.out.println("USING: " + name);
        }

        @Override
        public void close() {
            open = false;
            System.out.println("CLOSED: " + name);
        }
    }

    public static void main(String[] args) {
        // Pattern 1: Manual lifecycle
        Resource r = new Resource("Manual");
        r.use();
        r.close();
        r = null; // reference gone — GC eligible

        // Pattern 2: try-with-resources (PREFERRED for AutoCloseable)
        try (Resource r2 = new Resource("AutoClose")) {
            r2.use();
        } // r2.close() called automatically here — even if exception thrown

        System.out.println("Done");
    }
}
// Output:
// CREATED: Manual
// USING: Manual
// CLOSED: Manual
// CREATED: AutoClose
// USING: AutoClose
// CLOSED: AutoClose
// Done

