import java.util.*;

public class Inventory {
    static class Product {
        String name; double price; int quantity;
        Product(String n, double p, int q) { name=n; price=p; quantity=q; }
    }

    private List<Product> products = new ArrayList<>();

    public void addProduct(Product p) { products.add(p); }

    public double totalValue() {
        double total = 0;
        for (Product p : products) total += p.price * p.quantity;
        return total;
    }

    public Product findMostExpensive() {
        if (products.isEmpty()) return null;
        Product max = products.get(0);
        for (Product p : products)
            if (p.price > max.price) max = p;
        return max;
    }

    public static void main(String[] args) {
        Inventory inv = new Inventory();
        inv.addProduct(new Product("Apple",   1.5,  100));
        inv.addProduct(new Product("Laptop", 999.0,   5));
        inv.addProduct(new Product("Pen",     0.5,  200));
        System.out.println(inv.totalValue());              // 5245.0
        System.out.println(inv.findMostExpensive().name);  // Laptop
    }
}

