problems.solutionCode:
public class PointDesign {

    static class MutablePoint {
        int x, y;
        MutablePoint(int x, int y) { this.x=x; this.y=y; }
        void setX(int x) { this.x = x; }
        void translate(int dx, int dy) { x+=dx; y+=dy; }
        public String toString() { return "(" + x + "," + y + ")"; }
    }

    static class ImmutablePoint {
        final int x, y;
        ImmutablePoint(int x, int y) { this.x=x; this.y=y; }
        ImmutablePoint translate(int dx, int dy) {
            return new ImmutablePoint(x + dx, y + dy);
        }
        public String toString() { return "(" + x + "," + y + ")"; }
    }

    public static void main(String[] args) {
        MutablePoint m = new MutablePoint(1, 2);
        m.translate(3, 4);
        System.out.println(m); // (4,6) — original mutated

        ImmutablePoint i  = new ImmutablePoint(1, 2);
        ImmutablePoint i2 = i.translate(3, 4);
        System.out.println(i);  // (1,2) — original unchanged!
        System.out.println(i2); // (4,6) — new object
    }
}

