import java.util.Date;

public class DateRange {
    private final Date start;
    private final Date end;

    public DateRange(Date start, Date end) {
        if (start.after(end)) throw new IllegalArgumentException("start must be <= end");
        this.start = new Date(start.getTime()); // defensive copy
        this.end   = new Date(end.getTime());
    }

    public Date getStart() { return new Date(start.getTime()); } // defensive copy
    public Date getEnd()   { return new Date(end.getTime()); }

    public static void main(String[] args) {
        Date s = new Date(1000000);
        Date e = new Date(2000000);
        DateRange dr = new DateRange(s, e);
        s.setTime(999);                              // mutate original
        System.out.println(dr.getStart().getTime()); // 1000000 — protected!
        Date leaked = dr.getStart();
        leaked.setTime(0);                           // mutate returned copy
        System.out.println(dr.getStart().getTime()); // 1000000 — still protected!
    }
}

