import java.util.Objects;

public class Pair<A, B> {
    private final A first;
    private final B second;

    public Pair(A first, B second) { this.first = first; this.second = second; }

    public A getFirst()  { return first; }
    public B getSecond() { return second; }

    public Pair<B, A> swap() { return new Pair<>(second, first); }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof Pair<?,?> p)) return false;
        return Objects.equals(first, p.first) && Objects.equals(second, p.second);
    }

    @Override
    public int hashCode() { return Objects.hash(first, second); }

    @Override
    public String toString() { return "(" + first + ", " + second + ")"; }

    public static void main(String[] args) {
        Pair<String, Integer> p1 = new Pair<>("hello", 42);
        Pair<String, Integer> p2 = new Pair<>("hello", 42);
        Pair<Integer, String> p3 = p1.swap();
        System.out.println(p1.equals(p2));  // true
        System.out.println(p3.getFirst());  // 42
        System.out.println(p3.getSecond()); // hello
        System.out.println(p1);             // (hello, 42)
