        }
        // hashCode NOT overridden — uses identity hash
    }

    static class FixedKey {
        int id;
        FixedKey(int id) { this.id = id; }
        @Override public boolean equals(Object o) {
            return o instanceof FixedKey k && k.id == this.id;
        }
        @Override public int hashCode() { return Objects.hash(id); }
    }

    public static void main(String[] args) {
        Map<BrokenKey, String> broken = new HashMap<>();
        broken.put(new BrokenKey(1), "value");
        System.out.println(broken.get(new BrokenKey(1))); // null — BUG!

        Map<FixedKey, String> fixed = new HashMap<>();
        fixed.put(new FixedKey(1), "value");
        System.out.println(fixed.get(new FixedKey(1)));   // value — FIXED
    }
}

