import java.util.Objects;

public class Money {
    private final long cents;
    private final String currency;

    public Money(long cents, String currency) {
        if (cents < 0) throw new IllegalArgumentException("Negative money");
        this.cents    = cents;
        this.currency = currency;
    }

    public long   getCents()    { return cents; }
    public String getCurrency() { return currency; }

    public Money add(Money other) {
        if (!currency.equals(other.currency))
            throw new IllegalArgumentException("Currency mismatch: " + currency + " vs " + other.currency);
        return new Money(cents + other.cents, currency);
    }

    public Money multiply(int factor) {
        if (factor < 0) throw new IllegalArgumentException("Negative factor");
        return new Money(cents * factor, currency);
    }

    @Override public boolean equals(Object o) {
        if (!(o instanceof Money m)) return false;
        return cents == m.cents && currency.equals(m.currency);
    }
    @Override public int hashCode() { return Objects.hash(cents, currency); }
    @Override public String toString() { return String.format("%s %.2f", currency, cents / 100.0); }

    public static void main(String[] args) {
        Money price = new Money(999, "USD");
        Money tax   = new Money(80,  "USD");
        Money total = price.add(tax).multiply(2);
        System.out.println(total); // USD 21.58

        Money a = new Money(500, "USD");
